// ─── Extrair e validar mensagem do Evolution API ───
const body = $input.first().json;

// Ignorar mensagens enviadas pelo próprio bot
if (body?.data?.key?.fromMe === true) {
  return [];
}

// Ignorar mensagens de grupos
const remoteJid = body?.data?.key?.remoteJid || '';
if (remoteJid.includes('@g.us')) {
  return [];
}

// Ignorar eventos que não sejam mensagens
const event = body?.event || '';
if (!event.includes('messages')) {
  return [];
}

// Extrair dados da mensagem
const phone = remoteJid.replace('@s.whatsapp.net', '');
const pushName = body?.data?.pushName || 'Hóspede';

const message =
  body?.data?.message?.conversation ||
  body?.data?.message?.extendedTextMessage?.text ||
  body?.data?.message?.imageMessage?.caption ||
  body?.data?.message?.documentMessage?.caption ||
  '';

const hasMedia =
  !!body?.data?.message?.imageMessage ||
  !!body?.data?.message?.documentMessage;

const mediaType = body?.data?.message?.imageMessage
  ? 'image'
  : body?.data?.message?.documentMessage
  ? 'document'
  : null;

if (!phone) return [];

return [{
  json: {
    phone,
    pushName,
    message,
    remoteJid,
    hasMedia,
    mediaType,
    instanceName: body?.instance || 'Iene-teste',
    rawEvent: event
  }
}];

