// Parsear resposta da OpenAI
const aiResponse = $input.first().json;
const rawContent = aiResponse?.choices?.[0]?.message?.content || '{}';

let parsed = { intencao: 'duvida_geral', resposta: 'Olá! Como posso ajudar? 😊' };
try {
  // Remover blocos de markdown se existirem
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  console.log('Erro ao parsear JSON da IA:', e.message);
}

// Pegar dados da mensagem original do item anterior (passados via $('Extrair Dados da Mensagem'))
const msgData = $('🔍 Extrair Dados da Mensagem').first().json;

return [{
  json: {
    ...msgData,
    intencao: parsed.intencao || 'duvida_geral',
    respostaIA: parsed.resposta || 'Olá! Como posso ajudar? 😊'
  }
}];

// Mensagem de boas-vindas para nova reserva
const { pushName, phone } = $json;
const texto = `Olá, ${pushName}! 🏠 Seja muito bem-vindo(a)!

Sua reserva foi confirmada com sucesso. Estou aqui para garantir a melhor estadia possível.

Para finalizar seu cadastro e liberar o acesso ao imóvel, preciso de alguns documentos:

📋 *Envie por aqui:*
• Foto do RG ou CNH (frente e verso)
• Foto segurando o documento (selfie)

Assim que receber, confirmarei tudo e um dia antes do check-in te mando o endereço completo e o código da fechadura. 🔑

Qualquer dúvida, pode chamar! 😊`;

return [{ json: { ...$json, mensagemFinal: texto } }];

// Confirmação de recebimento de documentos
const { pushName } = $json;
const texto = `✅ Perfeito, ${pushName}! Documentos recebidos com sucesso!

Vou verificar tudo e em breve confirmo seu cadastro.

Um dia antes do seu check-in vou te enviar:
🏠 Endereço completo
🔑 Código da fechadura
🕐 Horário de entrada
ℹ️ Regras e dicas do imóvel

Qualquer dúvida, pode chamar! 😊`;

return [{ json: { ...$json, mensagemFinal: texto } }];

// Instruções de check-in (quando hóspede pergunta)
// ⚠️ EDITE os dados do seu imóvel abaixo
const { pushName } = $json;

const ENDERECO = 'Rua Exemplo, 123, Apto 301 - Bairro, Cidade - CEP 00000-000';
const CODIGO_FECHADURA = '1234#';
const HORARIO_CHECKIN = '15h00';
const HORARIO_CHECKOUT = '11h00';
const WIFI_NOME = 'ZapCentral_Guest';
const WIFI_SENHA = 'zapcentral2024';

const texto = `Olá, ${pushName}! Aqui estão todas as informações de check-in: 🏠

📍 *Endereço:*
${ENDERECO}

🔑 *Código da fechadura:*
${CODIGO_FECHADURA}

🕐 *Horários:*
• Check-in: a partir das ${HORARIO_CHECKIN}
• Check-out: até ${HORARIO_CHECKOUT}

📶 *Wi-Fi:*
Rede: ${WIFI_NOME}
Senha: ${WIFI_SENHA}

⚠️ *Regras importantes:*
• Não é permitido fumar no imóvel
• Número máximo de hóspedes conforme reserva
• Em caso de problemas, me avise imediatamente

Boa estadia! 🌟 Qualquer dúvida, estou aqui!`;

return [{ json: { ...$json, mensagemFinal: texto } }];

// Alerta de manutenção para o gestor
// ⚠️ EDITE o número do gestor abaixo
const { pushName, message, phone } = $json;

const NUMERO_GESTOR = '554588219903'; // ← NÚMERO DO GESTOR

const textoHospede = `Olá, ${pushName}! Recebi seu relato e já acionei o suporte. 🔧\n\nNosso responsável entrará em contato em breve para resolver o problema.\nLamentamos o inconveniente e agradecemos a compreensão! 🙏`;

const textoGestor = `⚠️ *MANUTENÇÃO SOLICITADA*\n\nHóspede: ${pushName}\nTelefone: ${phone}\nRelato: ${message}\n\nPor favor, entre em contato com o hóspede para resolver.`;

return [
  { json: { ...$json, mensagemFinal: textoHospede, phoneGestor: NUMERO_GESTOR, mensagemGestor: textoGestor } }
];

// Verificar se contato existe no Chatwoot
const result = $input.first().json;
const msgData = $('📋 Parsear Resposta da IA').first().json;

const contacts = result?.payload || [];
const existing = contacts.find(c =>
  c.phone_number && c.phone_number.replace(/\D/g, '').endsWith(msgData.phone.slice(-8))
);

return [{
  json: {
    ...msgData,
    chatwootContactId: existing?.id || null,
    contactExists: !!existing
  }
}];

// Consolidar contact_id (de contato existente ou recém-criado)
const input = $input.first().json;

// Se veio do "Criar Contato", pega o ID da resposta
if (input?.id) {
  const msgData = $('❓ Contato já existe?').first().json;
  return [{ json: { ...msgData, chatwootContactId: input.id } }];
}

// Se veio do IF (contato já existia)
return [{ json: input }];

// Filtrar hóspedes com check-in amanhã
// ⚠️ Requer coluna 'checkin_date' (DATE) na tabela leads
const leads = $input.first().json;

const amanha = new Date();
amanha.setDate(amanha.getDate() + 1);
const dataAmanha = amanha.toISOString().split('T')[0]; // YYYY-MM-DD

if (!Array.isArray(leads)) return [];

const hospedesAmanha = leads.filter(l => l.checkin_date === dataAmanha);

return hospedesAmanha.map(hospede => ({
  json: {
    phone: hospede.phone?.replace(/\D/g, '') || '',
    pushName: hospede.name || 'Hóspede',
    instanceName: 'Iene-teste',
    // ⚠️ EDITE os dados do imóvel abaixo
    mensagemFinal:
      `Olá, ${hospede.name}! 🌟 Seu check-in é *amanhã*! Aqui estão as informações de acesso:\n\n` +
      `📍 *Endereço:* Rua Exemplo, 123, Apto 301 - Cidade\n` +
      `🔑 *Código da fechadura:* 1234#\n` +
      `🕐 *Horário de entrada:* a partir das 15h00\n` +
      `🕙 *Horário de saída:* até 11h00\n` +
      `📶 *Wi-Fi:* ZapCentral_Guest | Senha: zapcentral2024\n\n` +
      `Qualquer dúvida, pode chamar! Boa estadia! 🏠✨`
  }
}));

// Filtrar hóspedes com checkout hoje
// ⚠️ Requer coluna 'checkout_date' (DATE) na tabela leads
const leads = $input.first().json;

const hoje = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

if (!Array.isArray(leads)) return [];

const hospedesHoje = leads.filter(l => l.checkout_date === hoje);

return hospedesHoje.map(hospede => ({
  json: {
    phone: hospede.phone?.replace(/\D/g, '') || '',
    pushName: hospede.name || 'Hóspede',
    instanceName: 'Iene-teste',
    mensagemFinal:
      `Olá, ${hospede.name}! 😊 Esperamos que sua estadia tenha sido incrível!\n\n` +
      `Gostaríamos muito de saber sua opinião:\n\n` +
      `⭐ *Numa escala de 0 a 10, quanto você recomendaria nossa propriedade para amigos e familiares?*\n\n` +
      `Sua avaliação nos ajuda a melhorar e significa muito para nós! 🙏\n\n` +
      `Se puder também deixar uma avaliação no Airbnb/Booking, ficamos muito gratos! 🌟`
  }
}));
